  "notableFindings": [
    "NavRouter is deprecated (moved to discontinued components) — use NavPathStack + navDestination() for routing instead",
    "BottomTabBarStyle provides icon+text bottom tab style without animation; SubTabBarStyle provides text+underline style with animation",
    "List + LazyForEach enables lazy loading for long-list performance; ForEach creates all children eagerly",
    "GridRow/GridCol support responsive breakpoints (xs/sm/md/lg/xl/xxl) for multi-device layouts",
    "Scroll nesting List without explicit List size forces full child loading — specify List dimensions for lazy loading",
    "Flex has a secondary layout pass — prefer Column/Row for performance-critical scenarios",
    "Bottom tab bar (EatWhat 5 tabs) should use Tabs + BottomTabBarStyle with BarPosition.End",
    "Tabs from API 11 default to safe-area inset on bottom edge"
  ],
  "missingApis": [
    "NavRouter — deprecated, no dedicated doc in active components; moved to discontinued components directory (reference only; use NavPathStack instead)"
  ]
}

