      "anchor": "canvas",
      "status": "found"
    },
    {
      "name": "Path2D / CanvasPath2D",
      "purpose": "路径对象，通过接口描述路径并通过Canvas.stroke/fill绘制；支持从SVG路径字符串构造",
      "anchor": "path2d--canvaspath2d",
      "status": "found"
    },
    {
      "name": "CanvasRenderingContext2D",
      "purpose": "Canvas画布的2D绘制上下文，提供形状、文本、图片绘制方法和属性（fillStyle, lineWidth, strokeStyle等）",
      "anchor": "canvasrenderingcontext2d",
      "status": "found"
    },
    {
      "name": "animateTo",
      "purpose": "显式动画接口，通过闭包代码中的状态变化插入过渡动效；支持duration, curve, delay, iterations等参数",
      "anchor": "animateto",
      "status": "found"
    },
    {
      "name": "Animator / AnimatorOptions",
      "purpose": "组件动画模块，提供创建、播放、暂停、反向播放、结束动画的能力；通过onFrame回调驱动值变化",
      "anchor": "animator--animatoroptions",
      "status": "found"
    },
    {
      "name": "rotation (rotate transform)",
      "purpose": "对Canvas画布坐标轴进行顺时针旋转，单位为弧度",
      "anchor": "rotation-rotate-transform",
      "status": "found"
    },
    {
      "name": "translate / scale (canvas transform)",
      "purpose": "Canvas画布原点平移和缩放变换；translate移动原点，scale缩放后续绘制，transform支持任意矩阵变换",
      "anchor": "translate--scale-canvas-transform",
      "status": "found"
    }
  ],
  "notableFindings": [
    "animateTo全局函数从API 18废弃，推荐使用this.getUIContext()?.animateTo()",
    "Animator.create()从API 18废弃，推荐使用UIContext.createAnimator()",
    "Canvas旋转单位为弧度，需用 degree * Math.PI / 180 转换",
    "OffscreenCanvas可用于离屏渲染生成分享卡片，通过transferToImageBitmap传回主Canvas",
    "Canvas组件最大面积10000px*10000px，宽高超过8000px时使用CPU渲染性能下降"
  ],
  "missingApis": []
}

