      "status": "found"
    },
    {
      "name": "SaveButton",
      "purpose": "Security control that grants temporary write-to-gallery permission on user tap",
      "anchor": "savebutton",
      "status": "found"
    },
    {
      "name": "Canvas (off-screen rendering)",
      "purpose": "Render the share card UI and extract it as a PixelMap via getPixelMap or transferToImageBitmap",
